function switchTab(t){document.querySelectorAll('.tab-content').forEach(e=>e.classList.remove('active'));document.querySelectorAll('.nav-tab').forEach(e=>e.classList.remove('active'));document.getElementById('tab-'+t).classList.add('active');var tabs=document.querySelectorAll('.nav-tab');for(var i=0;i<tabs.length;i++){if(tabs[i].textContent.trim()&&tabs[i].getAttribute('onclick')&&tabs[i].getAttribute('onclick').indexOf("'"+t+"'")>-1){tabs[i].classList.add('active');break;}}}
function fmt(n){return new Intl.NumberFormat('en-IN').format(n);}
function escapeHTML(s){return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#39;');}

